def render_lightweight_option_selector(
    options: list,
    state_key: str,
    *,
    format_func=None,
    helper_text: str = "",
    widget_label: str = "",
):
    if not options:
        return None

    current_value = st.session_state.get(state_key, options[0])
    if current_value not in options:
        current_value = options[0]
    st.session_state[state_key] = current_value

    inject_lightweight_option_selector_css(state_key)

    selector_key = f"{state_key}__selector"
    selected_value = st.radio(
        widget_label or state_key,
        options=options,
        index=options.index(current_value),
        format_func=format_func,
        horizontal=True,
        key=selector_key,
        label_visibility="collapsed",
    )
    st.session_state[state_key] = selected_value
    if helper_text:
        st.caption(helper_text)
    return selected_value


def render_standard_step_navigator(
    option_keys: list[str],
    state_key: str,
    widget_label_key: str = "layout_step_navigation",
) -> str:
    if not option_keys:
        return ""

    current_value = st.session_state.get(state_key, option_keys[0])
    if current_value not in option_keys:
        current_value = option_keys[0]
    st.session_state[state_key] = current_value

    inject_standard_step_navigator_css(state_key)

    selector_key = f"{state_key}__selector"
    selected_value = st.radio(
        t(widget_label_key),
        options=option_keys,
        index=option_keys.index(current_value),
        format_func=standard_layout_section_label,
        horizontal=True,
        key=selector_key,
        label_visibility="collapsed",
    )
    st.session_state[state_key] = selected_value

    selected_index = option_keys.index(selected_value)
    total_steps = len(option_keys)
    progress_ratio = (selected_index + 1) / total_steps if total_steps else 0.0
    progress_percent = int(round(progress_ratio * 100))

    render_html_block(
        f"""
        <div class="standard-step-progress-shell">
            <div class="standard-step-progress-head">
                <div class="standard-step-progress-label">
                    {escape(t("layout_step_progress", current=selected_index + 1, total=total_steps, current_label=standard_layout_section_label(selected_value)))}
                </div>
                <div class="standard-step-progress-badge">{progress_percent}%</div>
            </div>
            <div class="standard-step-progress-track">
                <div class="standard-step-progress-fill" style="width: {progress_percent}%;"></div>
            </div>
        </div>
        """
    )

    back_disabled = selected_index <= 0
    next_disabled = selected_index >= total_steps - 1

    back_label = (
        t("layout_back_step_start")
        if back_disabled
        else t("layout_back_step_to", target=standard_layout_section_label(option_keys[selected_index - 1]))
    )
    next_label = (
        t("layout_next_step_done")
        if next_disabled
        else t("layout_next_step_to", target=standard_layout_section_label(option_keys[selected_index + 1]))
    )

    back_col, next_col = st.columns(2)
    with back_col:
        if st.button(
            back_label,
            key=f"{state_key}__back_step",
            use_container_width=True,
            disabled=back_disabled,
        ):
            st.session_state[state_key] = option_keys[selected_index - 1]
            st.rerun()
    with next_col:
        if st.button(
            next_label,
            key=f"{state_key}__next_step",
            use_container_width=True,
            disabled=next_disabled,
        ):
            st.session_state[state_key] = option_keys[selected_index + 1]
            st.rerun()

    return selected_value


def render_standard_workspace_picker(
    daily_data: pd.DataFrame,
    intraday_data: pd.DataFrame | None,
    tickers: list[str],
    lens_meta: dict | None = None,
) -> None:
    lang_zh = get_lang() == "繁體中文"
    if not tickers:
        return
    default_ticker = st.session_state.get("dashboard_standard_focus_ticker", tickers[0])
    if default_ticker not in tickers:
        default_ticker = tickers[0]
    selected_ticker = st.selectbox(
        "選擇一個工作台" if lang_zh else "Choose one workspace",
        options=tickers,
        index=tickers.index(default_ticker),
        format_func=display_ticker_label,
        key="dashboard_standard_focus_ticker",
    )
    st.caption(
        "標準模式一次只打開一個工作台，閱讀壓力會小很多。"
        if lang_zh
        else "Standard mode opens one workspace at a time to keep the reading flow simpler."
    )
    render_ticker_page(daily_data, intraday_data, selected_ticker, lens_meta=lens_meta, selected_count=len(tickers))


def render_ticker_workspace_tabs(
    daily_data: pd.DataFrame,
    intraday_data: pd.DataFrame | None,
    tickers: list[str],
    lens_meta: dict | None = None,
) -> None:
    if not tickers:
        return
    lang_zh = get_lang() == "繁體中文"
    selected_ticker = render_lightweight_option_selector(
        tickers,
        "dashboard_workspace_focus_ticker",
        format_func=display_ticker_label,
        helper_text=(
            "工作台改成一次只載入一檔，切換會比整排 tabs 更順。"
            if lang_zh else
            "The workspace now loads one ticker at a time so switching stays responsive."
        ),
        widget_label="ticker-workspaces-selector",
    )
    if selected_ticker:
        render_ticker_page(daily_data, intraday_data, selected_ticker, lens_meta=lens_meta, selected_count=len(tickers))



