def is_taiwan_active_etf(ticker: str) -> bool:
    ticker_upper = str(ticker or "").upper().strip()
    if not is_taiwan_ticker(ticker_upper):
        return False
    code = ticker_base_code(ticker_upper)
    return len(code) == 6 and code.endswith("A")


def _safe_float(value, default: float = float("nan")) -> float:
    try:
        if value is None:
            return default
        if isinstance(value, str):
            raw = value.strip()
            if not raw:
                return default

            normalized = (
                raw.replace(",", "")
                .replace("%", "")
                .replace("％", "")
                .replace("＋", "")
                .replace("+", "")
                .replace("--", "")
                .replace("−", "-")
                .replace("－", "-")
                .strip()
            )
            if normalized.lower() in {"", "-", "nan", "none", "null", "n/a"}:
                return default

            date_like = normalized.replace(".", "/")
            if re.fullmatch(r"\d{2,4}[/-]\d{1,2}[/-]\d{1,2}", date_like):
                return default
            if re.fullmatch(r"\d{5,8}", normalized):
                return default

            try:
                return float(normalized)
            except Exception:
                match = re.search(r"[-+]?(?:\d+\.\d+|\d+)", normalized)
                if match:
                    return float(match.group(0))
                return default
        return float(value)
    except Exception:
        return default


def _format_signed_integer(value: float, unit: str = "") -> str:
    if value is None or pd.isna(value):
        return "—"
    prefix = "+" if value > 0 else ""
    return f"{prefix}{int(round(value)):,}{unit}"


def _format_percent_compact(value: float, digits: int = 2) -> str:
    if value is None or pd.isna(value):
        return "—"
    return f"{value:+.{digits}f}%"


def _ensure_active_etf_snapshot_db() -> None:
    ACTIVE_ETF_TRACKER_SNAPSHOT_DB.parent.mkdir(parents=True, exist_ok=True)
    with sqlite3.connect(ACTIVE_ETF_TRACKER_SNAPSHOT_DB) as conn:
        conn.execute(
            """
            create table if not exists etf_holdings_snapshots (
                ticker text not null,
                snapshot_date text not null,
                holdings_json text not null,
                source text not null default '',
                created_at text not null default current_timestamp,
                primary key (ticker, snapshot_date)
            )
            """
        )
        conn.commit()


def _normalize_holdings_records(records: list[dict], max_items: int = 15) -> list[dict]:
    cleaned: list[dict] = []
    for item in records or []:
        name = str(item.get("name", "")).strip()
        weight = _safe_float(item.get("weight"))
        if not name or pd.isna(weight):
            continue
        if abs(weight) <= 1.5:
            weight *= 100.0
        cleaned.append({"name": name, "weight": float(weight)})
    cleaned.sort(key=lambda row: row["weight"], reverse=True)
    return cleaned[:max_items]


def _snapshot_today_string() -> str:
    return datetime.now(TW_TZ).date().isoformat()


def _upsert_active_etf_snapshot(ticker: str, records: list[dict], source: str = ACTIVE_ETF_HOLDINGS_SOURCE_LABEL) -> None:
    normalized = _normalize_holdings_records(records)
    if not normalized:
        return
    _ensure_active_etf_snapshot_db()
    snapshot_date = _snapshot_today_string()
    with sqlite3.connect(ACTIVE_ETF_TRACKER_SNAPSHOT_DB) as conn:
        conn.execute(
            """
            insert into etf_holdings_snapshots (ticker, snapshot_date, holdings_json, source)
            values (?, ?, ?, ?)
            on conflict(ticker, snapshot_date) do update set
                holdings_json = excluded.holdings_json,
                source = excluded.source,
                created_at = current_timestamp
            """,
            (str(ticker).upper(), snapshot_date, json.dumps(normalized, ensure_ascii=False), source),
        )
        conn.commit()


def _load_previous_active_etf_snapshot(ticker: str) -> tuple[list[dict], str | None, str]:
    _ensure_active_etf_snapshot_db()
    current_date = _snapshot_today_string()
    with sqlite3.connect(ACTIVE_ETF_TRACKER_SNAPSHOT_DB) as conn:
        row = conn.execute(
            """
            select holdings_json, snapshot_date, source
            from etf_holdings_snapshots
            where ticker = ? and snapshot_date < ?
            order by snapshot_date desc
            limit 1
            """,
            (str(ticker).upper(), current_date),
        ).fetchone()
    if not row:
        return [], None, ""
    try:
        payload = json.loads(row[0]) if row[0] else []
    except Exception:
        payload = []
    return payload, row[1], row[2] or ""


def _load_latest_active_etf_snapshot(ticker: str) -> tuple[list[dict], str | None, str]:
    _ensure_active_etf_snapshot_db()
    with sqlite3.connect(ACTIVE_ETF_TRACKER_SNAPSHOT_DB) as conn:
        row = conn.execute(
            """
            select holdings_json, snapshot_date, source
            from etf_holdings_snapshots
            where ticker = ?
            order by snapshot_date desc
            limit 1
            """,
            (str(ticker).upper(),),
        ).fetchone()
    if not row:
        return [], None, ""
    try:
        payload = json.loads(row[0]) if row[0] else []
    except Exception:
        payload = []
    return payload, row[1], row[2] or ""


def _pick_name_and_weight_columns(df: pd.DataFrame) -> tuple[str | None, str | None]:
    columns = list(df.columns)
    lowered = {str(col).lower(): col for col in columns}
    for candidate in ("holding", "name", "company", "symbol", "ticker"):
        for lower_name, original in lowered.items():
            if candidate in lower_name:
                name_col = original
                break
        else:
            continue
        break
    else:
        name_col = None

    weight_col = None
    for candidate in ("weight", "holding", "percent", "percentage", "portfolio"):
        for lower_name, original in lowered.items():
            if candidate in lower_name:
                weight_col = original
                break
        if weight_col is not None:
            break

    if name_col is None and len(columns) >= 1:
        first = columns[0]
        if not pd.api.types.is_numeric_dtype(df[first]):
            name_col = first

    if weight_col is None:
        numeric_candidates = [col for col in columns if pd.api.types.is_numeric_dtype(df[col])]
        if numeric_candidates:
            weight_col = numeric_candidates[0]
        elif len(columns) >= 2:
            weight_col = columns[-1]
    return name_col, weight_col




def _is_numericish_holding_token(value) -> bool:
    raw = str(value or "").strip().replace(",", "").replace("%", "")
    if not raw:
        return False
    try:
        float(raw)
        return True
    except Exception:
        return False


def _contains_cjk_text(value: str) -> bool:
    return bool(re.search(r"[\u3400-\u4dbf\u4e00-\u9fff\uf900-\ufaff]", str(value or "")))


def _http_headers(accept: str = "application/json,text/plain,*/*") -> dict[str, str]:
    return {
        "User-Agent": (
            "Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
            "AppleWebKit/537.36 (KHTML, like Gecko) "
            "Chrome/125.0.0.0 Safari/537.36"
        ),
        "Accept": accept,
        "Accept-Language": "zh-TW,zh;q=0.9,en-US;q=0.8,en;q=0.7",
        "Cache-Control": "no-cache",
        "Pragma": "no-cache",
        "Connection": "close",
    }


def _build_ssl_contexts() -> list[ssl.SSLContext]:
    contexts: list[ssl.SSLContext] = []

    if truststore is not None:
        try:
            contexts.append(truststore.SSLContext(ssl.PROTOCOL_TLS_CLIENT))
        except Exception:
            pass

    if certifi is not None:
        try:
            contexts.append(ssl.create_default_context(cafile=certifi.where()))
        except Exception:
            pass

    try:
        contexts.append(ssl.create_default_context())
    except Exception:
        pass

    deduped: list[ssl.SSLContext] = []
    seen: set[int] = set()
    for context in contexts:
        marker = id(context)
        if marker not in seen:
            deduped.append(context)
            seen.add(marker)
    return deduped


def _read_request_bytes(
    request: Request,
    timeout: int = 20,
    *,
    allow_insecure_fallback: bool = True,
) -> tuple[bytes, int]:
    last_error: Exception | None = None
    contexts = _build_ssl_contexts()
    if allow_insecure_fallback:
        contexts.append(ssl._create_unverified_context())

    for context in contexts:
        try:
            with urlopen(request, timeout=timeout, context=context) as response:
                return response.read(), int(getattr(response, "status", 200) or 200)
        except HTTPError:
            raise
        except Exception as exc:
            last_error = exc
            continue

    if last_error is not None:
        raise last_error
    raise RuntimeError("Unable to open request.")


def _open_url_bytes(url: str, timeout: int = 20, accept: str = "application/json,text/plain,*/*") -> bytes:
    request = Request(url, headers=_http_headers(accept=accept), method="GET")
    raw, _ = _read_request_bytes(request, timeout=timeout)
    return raw


def _decode_response_bytes(raw: bytes) -> str:
    if raw is None:
        return ""
    if isinstance(raw, str):
        return raw
    for encoding in ("utf-8-sig", "utf-8", "utf-16", "utf-16-le", "utf-16-be", "cp950", "big5", "latin-1"):
        try:
            return raw.decode(encoding)
        except Exception:
            continue
    return raw.decode("utf-8", errors="replace")


def _parse_json_text(raw_text: str):
    text_value = str(raw_text or "").strip()
    if not text_value:
        raise ValueError("Empty JSON payload.")
    text_value = text_value.lstrip("\ufeff")
    try:
        return json.loads(text_value)
    except json.JSONDecodeError:
        match = re.search(r"(\{.*\}|\[.*\])", text_value, re.S)
        if match:
            return json.loads(match.group(1))
        raise


def _fetch_text_url(url: str, timeout: int = 12, accept: str = "text/html,application/json,text/plain,*/*") -> str:
    return _decode_response_bytes(_open_url_bytes(url, timeout=timeout, accept=accept))


def _fetch_json_url(url: str, timeout: int = 12):
    return _parse_json_text(_fetch_text_url(url, timeout=timeout, accept="application/json,text/plain,*/*"))


def _twse_request_json(url: str) -> dict:
    return _fetch_json_url(url, timeout=20)



def _parse_twse_etf_flow_payload(payload: dict) -> pd.DataFrame:
    data = payload.get("data") or []
    fields = payload.get("fields") or []
    if not data or not fields:
        return pd.DataFrame()
    df = pd.DataFrame(data, columns=fields[: len(data[0])])
    rename_map = {}
    for col in df.columns:
        col_text = str(col)
        if "證券代號" in col_text or col_text == "代號":
            rename_map[col] = "code"
        elif "證券名稱" in col_text or col_text == "名稱":
            rename_map[col] = "name"
        elif "外陸資買進股數" in col_text or ("外資" in col_text and "買進股數" in col_text):
            rename_map[col] = "foreign_buy"
        elif "外陸資賣出股數" in col_text or ("外資" in col_text and "賣出股數" in col_text):
            rename_map[col] = "foreign_sell"
        elif "外陸資買賣超股數" in col_text or ("外資" in col_text and "買賣超股數" in col_text):
            rename_map[col] = "foreign_net"
        elif "投信買進股數" in col_text:
            rename_map[col] = "trust_buy"
        elif "投信賣出股數" in col_text:
            rename_map[col] = "trust_sell"
        elif "投信買賣超股數" in col_text:
            rename_map[col] = "trust_net"
        elif "自營商買賣超股數" in col_text and "自行買賣" not in col_text and "避險" not in col_text:
            rename_map[col] = "dealer_net"
        elif "自營商自行買賣買進股數" in col_text:
            rename_map[col] = "dealer_self_buy"
        elif "自營商自行買賣賣出股數" in col_text:
            rename_map[col] = "dealer_self_sell"
        elif "自營商自行買賣買賣超股數" in col_text:
            rename_map[col] = "dealer_self_net"
        elif "自營商避險買進股數" in col_text:
            rename_map[col] = "dealer_hedge_buy"
        elif "自營商避險賣出股數" in col_text:
            rename_map[col] = "dealer_hedge_sell"
        elif "自營商避險買賣超股數" in col_text:
            rename_map[col] = "dealer_hedge_net"
        elif "三大法人買賣超股數" in col_text:
            rename_map[col] = "three_net"
    df = df.rename(columns=rename_map)

    for col in (
        "foreign_buy", "foreign_sell", "foreign_net",
        "trust_buy", "trust_sell", "trust_net",
        "dealer_net", "dealer_self_buy", "dealer_self_sell", "dealer_self_net",
        "dealer_hedge_buy", "dealer_hedge_sell", "dealer_hedge_net", "three_net",
    ):
        if col in df.columns:
            df[col] = pd.to_numeric(df[col].astype(str).str.replace(",", "", regex=False), errors="coerce")
    return df


@st.cache_data(ttl=300, show_spinner=False)
def fetch_twse_etf_institutional_flow(ticker: str) -> dict:
    """Fetch TWSE T86 institutional flow for a listed ETF.

    The TWSE T86 report is published after market close and the ETF filter can
    vary across TWSE response paths. Try the ETF filter first, then fall back to
    the all-securities T86 report so active ETFs are not missed.
    """
    code = ticker_base_code(ticker).upper().strip()
    today = datetime.now(TW_TZ).date()
    errors: list[str] = []
    tried_urls: list[str] = []

    def _candidate_urls(date_str: str) -> list[tuple[str, str]]:
        base_paths = [
            "https://www.twse.com.tw/rwd/zh/fund/T86",
            "https://www.twse.com.tw/fund/T86",
            "https://www.twse.com.tw/exchangeReport/T86",
        ]
        variants = [
            ("ETF", "selectType=ETF"),
            ("ALL", "selectType=ALL"),
            ("ALLBUT0999", "selectType=ALLBUT0999"),
            ("no-filter", ""),
        ]
        urls: list[tuple[str, str]] = []
        for base in base_paths:
            for label, select_part in variants:
                query = f"response=json&date={date_str}"
                if select_part:
                    query = f"{query}&{select_part}"
                urls.append((label, f"{base}?{query}"))
        return urls

    for offset in range(0, 22):
        trade_date = today - pd.Timedelta(days=offset)
        date_str = trade_date.strftime("%Y%m%d")

        for source_label, url in _candidate_urls(date_str):
            tried_urls.append(url)
            try:
                payload = _twse_request_json(url)
                stat = str(payload.get("stat", "") or "")
                if stat.startswith("很抱歉") or "查無" in stat or "無資料" in stat:
                    continue

                frame = _parse_twse_etf_flow_payload(payload)
                if frame.empty or "code" not in frame.columns:
                    continue

                normalized_codes = frame["code"].astype(str).str.upper().str.strip()
                match = frame[normalized_codes == code]
                if match.empty:
                    compact_codes = normalized_codes.str.replace(r"[^0-9A-Z]", "", regex=True)
                    match = frame[compact_codes == re.sub(r"[^0-9A-Z]", "", code)]

                if match.empty:
                    continue

                row = match.iloc[0].to_dict()
                return {
                    "date": trade_date.isoformat(),
                    "record": row,
                    "source": f"TWSE T86 {source_label}",
                    "error": "",
                    "status": "ok",
                    "tried": tried_urls[-4:],
                }
            except Exception as exc:
                message = str(exc)
                if message not in errors:
                    errors.append(message)
                continue

    last_error = errors[-1] if errors else f"No T86 row matched ETF code {code} in the last 22 calendar days."
    return {
        "date": None,
        "record": {},
        "source": "TWSE T86",
        "error": last_error,
        "status": "missing",
        "tried": tried_urls[-6:],
    }


def _tracker_status_chip(label: str, tone: str) -> str:
    cls_map = {
        "up": "chip-buy",
        "down": "chip-sell",
        "neutral": "chip-hold",
        "info": "chip-info",
    }
    return f'<span class="chip {cls_map.get(tone, "chip-info")}">{escape(label)}</span>'


